            if j > 0 {
                dp[i + 1] = (prefix[i] - prefix[j - 1] + mod_val) % mod_val;
            } else {
                dp[i + 1] = prefix[i] % mod_val;
            }
            prefix[i + 1] = (prefix[i] + dp[i + 1]) % mod_val;
